text:
button.ui-button.ui-autocomplete-dropdown {
    border: none;
    background-color: transparent;
    overflow: hidden;
    .box-shadow(none);
    .border-left-radius(0px);
    &.ui-state-hover, .ui-state-focus {
        background: transparent;
        .border-left-radius(0px);
    }

    &.ui-state-active {
        .box-shadow(none);
    }

}

&-item {
  display: flex;
  align-items: center;
  background: @color-fill-grey-inverse;
  background: var(--am-multi-liner-item-background, @color-fill-grey-inverse);

  .a-input-content {
    padding-left: 2px;
  }
  .a-textarea-count-wrap {
    position: relative;
    bottom: 0;
    right: 0;
  }
}

& pre {
  height: calc(~"100% - 28px");
  background: transparent !important;
  margin: 0 !important;
  text-shadow: none !important;
  & code {
    background: transparent;
    text-shadow: none !important;
    & .token.operator {
      background: transparent;
    }
  }
}

&.is-focused,
  &.is-focused.editor {
    .focus();
    background-color: @input-background-color-focus;

    border-color: @input-border-color-focus;
    box-shadow: none;

    .selection .region {
      background-color: @input-selection-color-focus;
    }
  }

&.showing {
	.placard-footer,
	.placard-header,
	.placard-popup {
		display: block;
		z-index: 1;
	}

	div.placard-field, input.placard-field, textarea.placard-field {
		background: @true-white;
		border: 1px solid @gray80;
		box-shadow: none;
		position: relative;
		z-index: 1;
	}
}

&.showing {
	.picker-footer,
	.picker-header,
	.picker-popup {
		display: block;
		z-index: 1;
	}

	input.picker-field, textarea.picker-field {
		background: @true-white;
		border: 1px solid @gray80;
		box-shadow: none;
		position: relative;
		z-index: 1;
	}
}

& when(@variationFlyoutScrolling) {
    .ui.flyout.left > .scrolling.content,
    .ui.flyout.right > .scrolling.content {
        max-height: @scrollingContentMaxHeightWithoutHeader;
    }
    .ui.flyout.left > .header + .scrolling.content,
    .ui.flyout.right > .header + .scrolling.content {
        max-height: @scrollingContentMaxHeight;
    }

    .ui.flyout.top > .scrolling.content,
    .ui.flyout.bottom > .scrolling.content {
        max-height: @scrollingContentMaxHeightTopBottom;
    }
}

& when (@variationContainerGrid) or (@variationContainerRelaxed) {
    .ui.ui.ui.grid.container {
        width: @largeMonitorGridWidth;
    }
    & when (@variationContainerRelaxed) {
        .ui.ui.ui.relaxed.grid.container {
            width: @largeMonitorRelaxedGridWidth;
        }
        & when (@variationContainerVeryRelaxed) {
            .ui.ui.ui.very.relaxed.grid.container {
                width: @largeMonitorVeryRelaxedGridWidth;
            }
        }
    }
}

& when (@variationContainerGrid) or (@variationContainerRelaxed) {
    .ui.ui.ui.grid.container {
        width: @computerGridWidth;
    }
    & when (@variationContainerRelaxed) {
        .ui.ui.ui.relaxed.grid.container {
            width: @computerRelaxedGridWidth;
        }
        & when (@variationContainerVeryRelaxed) {
            .ui.ui.ui.very.relaxed.grid.container {
                width: @computerVeryRelaxedGridWidth;
            }
        }
    }
}

& when (@variationContainerGrid) or (@variationContainerRelaxed) {
    .ui.ui.ui.grid.container {
        width: @mobileGridWidth;
    }
    & when (@variationContainerRelaxed) {
        .ui.ui.ui.relaxed.grid.container {
            width: @mobileRelaxedGridWidth;
        }
        & when (@variationContainerVeryRelaxed) {
            .ui.ui.ui.very.relaxed.grid.container {
                width: @mobileVeryRelaxedGridWidth;
            }
        }
    }
}

& when (@variationContainerGrid) or (@variationContainerRelaxed) {
    .ui.ui.ui.grid.container {
        width: @tabletGridWidth;
    }
    & when (@variationContainerRelaxed) {
        .ui.ui.ui.relaxed.grid.container {
            width: @tabletRelaxedGridWidth;
        }
        & when (@variationContainerVeryRelaxed) {
            .ui.ui.ui.very.relaxed.grid.container {
                width: @tabletVeryRelaxedGridWidth;
            }
        }
    }
}

& when (@variationToastFloating) {
    &.floating,
    &.hoverfloating:hover {
        box-shadow: @floatingShadow;
        border: @toastBoxBorder;
    }
    & when (@variationToastInverted) {
        &.inverted.floating,
        &.inverted.hoverfloating:hover {
            box-shadow: @invertedFloatingShadow;
            border: @invertedToastBoxBorder;
        }
    }
}

& when (@variationMenuInverted) {
    .ui.inverted.tabbed.menu .active.item,
    .ui.inverted.tabbed.menu .active.item:hover {
        background: @invertedTabbedActiveBackground;
        border-color: @invertedTabbedBorderColor;
    }
    .ui.inverted.tabbed.menu .item:not(.active):hover {
        color: @invertedTabbedHoveredTextColor;
        background: transparent;
        cursor: pointer;
    }
}

& when (@variationRevealDisabled) {
    .ui.disabled.reveal:hover > .visible.visible.content {
        position: static !important;
        display: block !important;
        opacity: 1 !important;
        inset: 0 auto auto 0 !important;
        transform: none !important;
    }
    .ui.disabled.reveal:hover > .hidden.hidden.content {
        display: none !important;
    }
}

i.circular.icon {
    border-radius: 500em !important;
    line-height: 1 !important;
    padding: @circularPadding !important;
    box-shadow: @circularShadow;
    width: @circularSize !important;
    height: @circularSize !important;
    &.colored when (@variationIconColored) {
        box-shadow: @coloredBoxShadow;
    }
}

i.bordered.icon {
    line-height: 1;
    vertical-align: baseline;
    width: @borderedSize;
    height: @borderedSize;
    padding: @borderedVerticalPadding @borderedHorizontalPadding !important;
    box-shadow: @borderedShadow;
    &.colored when (@variationIconColored) {
        box-shadow: @coloredBoxShadow;
    }
}

> .btn {
  position: relative;
  float: left;
  // Bring the "active" button to the front
  &:hover,
  &:focus,
  &:active,
  &.active {
    z-index: 2;
  }
  &:focus {
    // Remove focus outline when dropdown JS adds it after closing the menu
    outline: none;
  }
}

&.right {
// Often used in conjunction with a button
// e.g., Clearing a search field, submitting a single input form (mailing list)
> [class*="icon-"] {
    right: .8em;
    left: auto;
  }

  > input {
    padding-right: 2.5em  !important;
    padding-left: 1em !important;
  }

  &:before { right: 2.5rem; }
}

nz-tree-virtual-scroll-view {
  position: relative;
  display: block;
  overflow: auto;
  transform: translateZ(0);
  will-change: scroll-position;
  contain: strict;
  -webkit-overflow-scrolling: touch;

  .ant-tree-list, .ant-tree-list-holder {
    height: 100%;
  }
}

body.panel-closing {
    .panel-overlay {
        display: block;
    }
    .views {
        .transition(@panelsDuration);
        -webkit-transition-property: -webkit-transform;
        -moz-transition-property: -moz-transform;
        transition-property: transform;
    }
    .panel.not-animated ~ .views {
        .transition(0ms);
    }
}

&.selected {
  color: @base-background-color;
  background: @button-background-color-selected;
  border: 1px solid @color !important;

  &:hover {
    color: @base-background-color !important;
    border: 1px solid @text-color-highlight !important;
    background: @color !important;
  }
}

&.disabled {
  @apply cursor-not-allowed;

  .title label {
    @apply text-color-text-disabled;
  }

  .value {
    @apply text-color-text-secondary;
  }

  svg.filter-box-icon {
    @apply fill-color-icon-disabled;
    @apply cursor-not-allowed;
  }
}

th {
  @apply overflow-hidden;
  @apply text-ellipsis;
  @apply whitespace-nowrap;
  @apply text-xs;
  @apply text-color-text-primary;
  @apply text-left;
  line-height: 1.7em;

  .overflow {
    @apply whitespace-nowrap;
    @apply overflow-hidden;
    @apply text-ellipsis;
  }
}

> .btn {
  position: relative;
  float: left;
  // Bring the "active" button to the front
  &:hover,
  &:focus,
  &:active,
  &.active {
    z-index: 2;
  }
  &:focus {
    // Remove focus outline when dropdown JS adds it after closing the menu
    outline: 0;
  }
}

&.disabled,
  &.disabled:hover,
  &.disabled:focus {
    background-color: @list-group-disabled-bg;
    color: @list-group-disabled-color;

    // Force color to inherit for custom content
    .list-group-item-heading {
      color: inherit;
    }
    .list-group-item-text {
      color: @list-group-disabled-text-color;
    }
  }

> a{
  border-width: 0 0 @nav-tabs-border-width-bottom;
  border-color: @nav-tabs-active-link-hover-border-color;
  background-color: transparent;

  &:hover,
  &:focus,
  &:active{
    border-width: 0 0 @nav-tabs-border-width-bottom;
    border-color: @nav-tabs-active-link-hover-border-color;
    background-color: transparent;
  }
}

&.selected {
  background: @selection-background !important;
  color: @- !important; .contrast(@global-text, 10%) !important;
  border-top: 1px solid @selection-border !important;
  border-bottom: 1px solid  @selection-border !important;

  .title,
  .subtitle {
    color: @- !important; .contrast(@global-text, 10%) !important;
  }
}

&-cell {
  cursor: pointer;

  &:hover {
    background-color: @calendar-body-cell-hover-bg-color;
    transition: background-color @calendar-transition-duration @calendar-transition-timing-function;
  }

  &-display {
    font: @calendar-body-cell-display-font;
    color: @calendar-title-color;
  }
}

&-cell {
  width: @calendar-card-cell-size;
  height: @calendar-card-cell-size;
  justify-content: center;
  font: @calendar-card-body-cell-font;
  box-sizing: border-box;

  &-display {
    width: @calendar-card-cell-value-size;
    line-height: @calendar-card-cell-value-size;
  }
}

&-card-area {
  border: @upload-flow-card-area-border;
  padding: @upload-flow-card-area-padding;
  margin-top: @upload-flow-card-area-margin-top;
  .hover-transition(border);

  &:hover {
    border-color: @upload-card-item-bg-border-color-hover;
    .hover-transition(border-color);
  }
}
